// LESSON: Reference Page 1 - Sortering och sokning.
// You will learn: Choose natural order, Comparator, binarySearch, and stable sorting.
class Prog2Reference431 {
  // EXEMPEL 1: Collections.sort anvander naturlig ordning for enkla typer.
  static java.util.List<String> sortedNames() {
    java.util.List<String> names = new java.util.ArrayList<String>(java.util.Arrays.asList("Bo", "Ada", "Cia"));
    java.util.Collections.sort(names);
    return names;
  }
  // EXEMPEL 2: Comparator kan sortera objekt pa ett valt falt.
  static class Book {
    final String title;
    final int year;
    Book(String title, int year) { this.title = title; this.year = year; }
  }
  static void sortBooksByYear(java.util.List<Book> books) {
    books.sort(java.util.Comparator.comparingInt(book -> book.year));
  }
  // EXEMPEL 3: binarySearch kraver att listan redan ar sorterad pa samma satt.
  static int findNumber() {
    java.util.List<Integer> numbers = java.util.Arrays.asList(2, 4, 6, 8);
    return java.util.Collections.binarySearch(numbers, 6);
  }
}
